import React, { useState, useEffect, useMemo } from 'react';
import { useSalon } from '../store/SalonContext';
import { TrendingUp, Zap, ShieldAlert, Plus, Trash2, Wallet, Lock, Unlock, AlertOctagon, BrainCircuit, Activity, EyeOff, ShieldCheck, Percent, ShoppingBag, Bell, Clock, X, Calendar, AlertTriangle, TrendingDown, FileBarChart, CreditCard, Banknote, Coffee, CheckCircle, Truck, ChefHat, Star, MessageCircle, UserPlus, CheckCircle2 } from 'lucide-react';
