              </div>

              {/* Geçmiş Özeti */}
              <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 flex justify-between items-center">
                  <div>
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Son İşlem</p>
                      <p className="text-sm font-bold text-slate-700">{customer.lastVisitDate ? customer.lastVisitDate.toLocaleDateString('tr-TR') : 'Henüz Yok'}</p>
                  </div>
                  <div className="text-right">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Toplam Harcama</p>
                      <p className="text-sm font-black text-slate-900">{(customer.dna.totalSpent || 0).toLocaleString()} TL</p>
                  </div>
              </div>
            </div>

            <div className="px-10 py-8 bg-slate-900 flex justify-between items-center print:hidden">
              <div className="flex gap-2">
                 <button 
                    onClick={() => sendWhatsApp(customer, 'REMINDER')} 
                    title="Otomatik Hatırlatma Mesajı Gönder" 
                    className={`p-4 rounded-2xl transition-all shadow-lg flex items-center gap-3 ${customer.isDue ? 'bg-rose-500 text-white hover:bg-rose-600 animate-pulse-subtle' : 'bg-emerald-500 text-white hover:bg-emerald-600'}`}
                 >
                    <MessageCircle size={20}/>
                    {customer.isDue && <span className="text-[9px] font-black uppercase">ÇAĞIR</span>}
                 </button>
                 <button onClick={() => setShowLoyaltyStampModal(customer)} title="Sadakat Kartı / Damga" className="p-4 bg-amber-500 text-white rounded-2xl hover:bg-amber-600 transition-all shadow-lg">
                    <Stamp size={20}/>
                 </button>
              </div>
              <div className="flex gap-2">
                 <button onClick={() => setShowGalleryModal(customer)} className="p-4 bg-white/10 text-rose-400 rounded-2xl hover:bg-white/20 transition-all" title="Galeri"><Image size={18}/></button>
                 <button onClick={() => setShowDietModal(customer)} className="p-4 bg-white/10 text-emerald-400 rounded-2xl hover:bg-white/20 transition-all" title="Vücut Analizi"><Scale size={18}/></button>
                 <button onClick={() => handleOpenEdit(customer)} className="p-4 text-white/40 hover:text-white transition-all" title="Düzenle"><Edit size={18}/></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* INFINITE SCROLL / LOAD MORE BUTTON */}
      {!isDemoMode && hasMoreCustomers && !filter && (
          <div className="flex justify-center py-10">
