                  tier: MembershipTier.BRONZE, 
                  branchId: 'b1', 
                  dna: { 
                      spendingPattern: 50, 
                      churnRisk: 10, 
                      packagePropensity: 50, 
                      luxuryTrendScore: 50, 
                      nextVisitPrediction: '', 
                      loyaltyPuan: Number(fd.get('loyaltyPuan')) || editItem?.dna?.loyaltyPuan || 0, 
                      totalSpent: editItem?.dna?.totalSpent || 0 
                  }, 
                  packages: [], 
                  history: editItem?.history || [], 
                  consentSigned: editItem?.consentSigned || false, 
                  signedDocuments: editItem?.signedDocuments || [], 
                  preferences: { music: 'Relax', drink: fd.get('drink') as string, notes: '' }, 
                  bodyAnalysis: editItem?.bodyAnalysis || [], 
                  gallery: editItem?.gallery || [],
                  specialPriceList: tempCustomPrices, // Özel fiyatları kaydet
                  loyaltyStamps: editItem?.loyaltyStamps || { skinCare: 0, nail: 0 },
                  dietPassword: fd.get('dietPassword') as string // DİYET ŞİFRESİ EKLENDİ
