                  <div className="space-y-4">
                      <label className="text-[10px] font-black uppercase text-slate-400 tracking-[0.4em] mb-2 block">PUAN</label>
                      <input name="loyaltyPuan" type="number" defaultValue={editItem?.dna?.loyaltyPuan || 0} className="w-full h-[108px] p-6 bg-slate-50 border-2 border-transparent rounded-[3rem] font-black text-3xl outline-none focus:border-slate-900 focus:bg-white transition-all shadow-inner text-center text-rose-500" />
