              <div className="pt-8 border-t border-slate-100 space-y-6">
                <div className="flex items-center gap-3">
                   <div className="bg-indigo-50 p-3 rounded-xl text-indigo-600"><Banknote size={24} /></div>
                   <div>
                       <h4 className="text-lg font-black italic">Kişiye Özel Fiyatlandırma</h4>
                       <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Sadece bu müşteriye özel fiyatlar</p>
                   </div>
                </div>

                <div className="bg-slate-50 rounded-[2rem] p-6 space-y-4 max-h-60 overflow-y-auto border border-slate-100">
                    {services.map(service => (
                        <div key={service.id} className="flex items-center justify-between">
