                                <p className="font-bold text-sm text-slate-700">{service.name}</p>
                                <p className="text-[10px] text-slate-400">Liste: {service.price} TL</p>
                            </div>
                            <input 
                                type="number" 
                                placeholder="Özel Fiyat"
                                className="w-24 p-2 rounded-xl border border-slate-200 text-right font-black outline-none focus:border-indigo-500"
                                value={tempCustomPrices[service.id] || ''}
                                onChange={(e) => {
                                    const val = e.target.value ? Number(e.target.value) : undefined;
                                    const newPrices = { ...tempCustomPrices };
                                    if (val !== undefined) newPrices[service.id] = val;
                                    else delete newPrices[service.id];
                                    setTempCustomPrices(newPrices);
                                }}
                            />
