              <div className="bg-white w-full max-w-4xl h-[90vh] rounded-[3rem] flex flex-col relative overflow-hidden animate-in zoom-in-95 shadow-3xl">
                  <div className="p-8 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                      <h3 className="text-3xl font-black italic text-slate-900 flex items-center gap-3">
                         <PenTool className="text-rose-500"/> {showConsentModal.title}
                      </h3>
                      <button onClick={() => setShowConsentModal({show: false, type: 'KVKK', title: ''})} className="p-4 bg-white rounded-full hover:bg-rose-500 hover:text-white transition-all shadow-sm"><X /></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-12 bg-slate-50">
                      <div className="bg-white p-12 shadow-sm border border-slate-200 min-h-full font-serif text-lg leading-relaxed text-slate-700 whitespace-pre-wrap rounded-[2rem]">
                          {showConsentModal.type === 'KVKK' ? kvkkText : 
                           showConsentModal.type === 'DIET_CONTRACT' ? "Diyet ve Sağlıklı Yaşam Danışmanlığı Hizmet Sözleşmesi..." : 
                           "İşlem Onam Metni..."}
                      </div>
                  </div>
                  <div className="p-8 bg-white border-t border-slate-100 flex flex-col gap-6">
                      <div className="border-2 border-dashed border-slate-300 rounded-3xl bg-slate-50 relative h-48 touch-none overflow-hidden group">
                          <canvas 
                              ref={signatureCanvasRef}
                              width={800}
                              height={192}
                              className="w-full h-full cursor-crosshair relative z-10"
                              onMouseDown={startDrawing}
                              onMouseMove={draw}
                              onMouseUp={() => setIsDrawing(false)}
                              onMouseLeave={() => setIsDrawing(false)}
                              onTouchStart={startDrawing}
                              onTouchMove={draw}
                              onTouchEnd={() => setIsDrawing(false)}
                          />
                          <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-20 group-hover:opacity-10 transition-opacity">
                              <p className="text-4xl font-black text-slate-300 uppercase tracking-[1em] rotate-[-5deg]">İmza Alanı</p>
                          </div>
                          <button 
                             onClick={() => {
                                 const canvas = signatureCanvasRef.current;
                                 const ctx = canvas?.getContext('2d');
                                 if(canvas && ctx) ctx.clearRect(0,0,canvas.width,canvas.height);
                             }}
                             className="absolute top-4 right-4 p-2 bg-slate-200 rounded-full text-slate-500 hover:bg-rose-500 hover:text-white transition-all z-20"
                          >
                             <RefreshCw size={16}/>
                          </button>
                      </div>
                      <button onClick={saveSignature} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black text-2xl shadow-xl hover:bg-emerald-500 transition-all flex items-center justify-center gap-4">
                          <BadgeCheck size={32}/> {showConsentModal.type === 'DIET_CONTRACT' ? 'Sözleşmeyi Onayla ve Başla' : 'Okudum, Onaylıyorum'}
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

